fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let n = nums.len();

    if n == 0 {
        return -1;
    }

    // Precompute prefix maximums: prefix_max[i] = max(nums[0..i])
    let mut prefix_max = vec![0; n];
    prefix_max[0] = nums[0];
    for i in 1..n {
        prefix_max[i] = prefix_max[i - 1].max(nums[i]);
    }

    // Precompute suffix minimums: suffix_min[i] = min(nums[i..n-1])
    let mut suffix_min = vec![0; n];
    suffix_min[n - 1] = nums[n - 1];
    for i in (0..n - 1).rev() {
        suffix_min[i] = suffix_min[i + 1].min(nums[i]);
    }

    // Iterate through all possible indices i
    for i in 0..n {
        // Unstable value for index i: max(nums[0..i]) - min(nums[i..n-1])
        let max_prefix = prefix_max[i];
        let min_suffix = suffix_min[i];

        let unstable_value = max_prefix - min_suffix;

        // Check if it is a stable index
        if unstable_value <= k {
            // Since we iterate from i=0 upwards, the first one found is the minimum stable index
            return i as i64;
        }
    }

    // If no stable index is found
    -1
}
